import Navbar from "./Components/Navbar";

const Header = () => {
    return (
        <header className="header">
            <Navbar />
            <h1>Welcome to My Website</h1>
            <img src="logo little lemon.png" alt="Logo" className="logo" />
        </header>
    );
}

export default Header;
